SELECT COUNT(email_id) AS important_email_count
FROM emails
WHERE labeled = 1;

SELECT user_id, COUNT(*) AS total_emails_sent
FROM emails
GROUP BY user_id;

SELECT COUNT(email_id) AS total_emails_sent
FROM message_logs
WHERE action = 'sent';

SELECT email_id, subject, date_sent
FROM emails
ORDER BY date_sent DESC;
